function initScrollReveal(){document.querySelectorAll("[data-animate]").forEach(el=>{el.classList.add("is-visible");el.style.opacity="1";el.style.transform="none";el.style.transition="none";el.style.animation="none"});if(window.innerWidth<=1024)return;const animatedElements=document.querySelectorAll("[data-animate]");if(!animatedElements.length)return;const observer=new IntersectionObserver(entries=>{entries.forEach(entry=>{if(entry.isIntersecting){entry.target.classList.add("is-visible");observer.unobserve(entry.target)}})},{threshold:.12,rootMargin:"0px 0px -60px 0px"});animatedElements.forEach(el=>observer.observe(el))}function initNavbarScroll(){const navbar=document.getElementById("navbar");if(!navbar)return;function handleNavScroll(){if(window.scrollY>80){navbar.classList.add("scrolled")}else{navbar.classList.remove("scrolled")}}handleNavScroll();window.addEventListener("scroll",handleNavScroll,{passive:true})}function initActiveNavLink(){const navLinks=document.querySelectorAll(".nav-links li a");if(!navLinks.length)return;const sections=Array.from(navLinks).map(link=>{const id=link.getAttribute("href").replace("#","");return document.getElementById(id)}).filter(Boolean);if(!sections.length)return;const observer=new IntersectionObserver(entries=>{entries.forEach(entry=>{if(entry.isIntersecting){const id=entry.target.getAttribute("id");navLinks.forEach(link=>link.classList.remove("active"));const activeLink=document.querySelector(`.nav-links a[href="#${id}"]`);if(activeLink)activeLink.classList.add("active")}})},{threshold:[.3,.7]});sections.forEach(section=>observer.observe(section))}function initMobileMenu(){const hamburger=document.getElementById("hamburger");const mobileMenu=document.getElementById("mobileMenu");if(!hamburger||!mobileMenu)return;let isOpen=false;function openMenu(){isOpen=true;hamburger.classList.add("open");mobileMenu.classList.add("open");mobileMenu.setAttribute("aria-hidden","false");hamburger.setAttribute("aria-expanded","true");document.body.style.overflow="hidden"}function closeMenu(){isOpen=false;hamburger.classList.remove("open");mobileMenu.classList.remove("open");mobileMenu.setAttribute("aria-hidden","true");hamburger.setAttribute("aria-expanded","false");document.body.style.overflow=""}hamburger.addEventListener("click",()=>{isOpen?closeMenu():openMenu()});const mobileLinks=mobileMenu.querySelectorAll("a");mobileLinks.forEach(link=>{link.addEventListener("click",closeMenu)});document.addEventListener("click",e=>{if(isOpen&&!mobileMenu.contains(e.target)&&!hamburger.contains(e.target)){closeMenu()}});document.addEventListener("keydown",e=>{if(e.key==="Escape"&&isOpen)closeMenu()})}function initCountUp(){const statNumbers=document.querySelectorAll("[data-count]");if(!statNumbers.length)return;let hasRun=false;function animateCount(el){const target=parseInt(el.getAttribute("data-count"),10);const duration=1500;const startTime=performance.now();function update(currentTime){const elapsed=currentTime-startTime;const progress=Math.min(elapsed/duration,1);const eased=1-Math.pow(1-progress,3);const current=Math.round(eased*target);el.textContent=current;if(progress<1){requestAnimationFrame(update)}else{el.textContent=target}}requestAnimationFrame(update)}const aboutSection=document.getElementById("about");if(!aboutSection)return;const observer=new IntersectionObserver(entries=>{entries.forEach(entry=>{if(entry.isIntersecting&&!hasRun){hasRun=true;statNumbers.forEach(el=>animateCount(el));observer.unobserve(aboutSection)}})},{threshold:.3});observer.observe(aboutSection)}function initSmoothScroll(){document.addEventListener("click",e=>{const anchor=e.target.closest('a[href^="#"]');if(!anchor)return;const href=anchor.getAttribute("href");if(href==="#")return;const target=document.querySelector(href);if(!target)return;e.preventDefault();const navbarHeight=80;const targetTop=target.getBoundingClientRect().top+window.scrollY-navbarHeight;window.scrollTo({top:targetTop,behavior:"smooth"})})}function initFooterYear(){const yearEl=document.getElementById("footer-year");if(yearEl){yearEl.textContent=(new Date).getFullYear()}}function initBackToTop(){const btn=document.querySelector(".footer-back-top");if(!btn)return;function handleBackToTopVisibility(){if(window.scrollY>400){btn.classList.add("visible")}else{btn.classList.remove("visible")}}handleBackToTopVisibility();window.addEventListener("scroll",handleBackToTopVisibility,{passive:true});btn.addEventListener("click",()=>{window.scrollTo({top:0,behavior:"smooth"})})}function initSkillTagsStagger(){const skillsSection=document.getElementById("skills");if(!skillsSection)return;let hasRun=false;const observer=new IntersectionObserver(entries=>{entries.forEach(entry=>{if(entry.isIntersecting&&!hasRun){hasRun=true;const tags=skillsSection.querySelectorAll(".tag");tags.forEach(tag=>tag.classList.add("tag-hidden"));tags.forEach((tag,index)=>{setTimeout(()=>{tag.classList.remove("tag-hidden");tag.classList.add("tag-visible")},index*40)});observer.unobserve(skillsSection)}})},{threshold:.15});observer.observe(skillsSection)}function initProjectCardsStagger(){setTimeout(()=>{const cards=document.querySelectorAll(".project-card[data-animate]");if(!cards.length)return;const observer=new IntersectionObserver(entries=>{entries.forEach(entry=>{if(entry.isIntersecting){entry.target.classList.add("is-visible");observer.unobserve(entry.target)}})},{threshold:.1,rootMargin:"0px 0px -40px 0px"});cards.forEach(card=>observer.observe(card))},100)}function throttle(fn,wait){let lastTime=0;return function(...args){const now=Date.now();if(now-lastTime>=wait){lastTime=now;fn.apply(this,args)}}}document.addEventListener("DOMContentLoaded",()=>{initScrollReveal();initNavbarScroll();initActiveNavLink();initMobileMenu();initCountUp();initSmoothScroll();initFooterYear();initBackToTop();initSkillTagsStagger();initProjectCardsStagger()});setTimeout(function(){document.querySelectorAll("[data-animate]").forEach(function(el){el.classList.add("is-visible");el.style.opacity="1";el.style.transform="none"})},1e3);